// Función para obtener el email del usuario actualmente logueado desde Firebase
function getCurrentUserEmail() {
    if (window.firebaseAuth && window.firebaseAuth.currentUser) {
        const email = window.firebaseAuth.currentUser.email;
        console.log('📧 Email obtenido de Firebase Auth:', email);
        return email;
    }
    if (window.getCurrentFirebaseEmail) {
        const email = window.getCurrentFirebaseEmail();
        console.log('📧 Email obtenido de getCurrentFirebaseEmail:', email);
        return email;
    }
    console.error('❌ No se pudo obtener el email del usuario logueado');
    return null;
}

// Función para obtener el UID del usuario actual
function getCurrentUserId() {
    if (window.firebaseAuth && window.firebaseAuth.currentUser) {
        return window.firebaseAuth.currentUser.uid;
    }
    return 'anonymous';
}

