// Mostrar sección específica
window.showSection = function(sectionId) {
    document.querySelectorAll('#reservation-section, #menu-section').forEach(section => {
        section.style.display = 'none';
    });
    document.getElementById(sectionId).style.display = 'block';
    
    if (sectionId === 'menu-section') {
        loadMenuItems();
        updateCartDisplay();
        showActiveReservation();
        loadHistory();
    }
};

// Cargar items del menú con imágenes
window.filterMenu = function(categoria) {
    loadMenuItems(categoria);
};

function loadMenuItems(categoria = 'all') {
    const container = document.getElementById('menu-items');
    if (!container) return;
    
    container.innerHTML = '';
    
    Object.entries(menuData).forEach(([id, item]) => {
        if (categoria === 'all' || item.categoria === categoria) {
            const card = document.createElement('div');
            card.className = 'menu-card';
            card.style.border = '1px solid #ddd';
            card.style.borderRadius = '10px';
            card.style.overflow = 'hidden';
            card.style.margin = '10px';
            card.style.padding = '0';
            card.style.backgroundColor = 'white';
            card.style.boxShadow = '0 2px 5px rgba(0,0,0,0.1)';
            card.style.transition = 'transform 0.3s';
            
            card.innerHTML = `
                <img src="${item.imagen}" alt="${item.nombre}" style="width: 100%; height: 150px; object-fit: cover;">
                <div style="padding: 12px;">
                    <div class="menu-info">
                        <h3 style="margin: 0 0 5px 0;">${item.nombre}</h3>
                        <p style="margin: 5px 0; font-size: 12px; color: #666;">${item.descripcion || ''}</p>
                        <span class="price" style="display: inline-block; margin-top: 8px; font-weight: bold; color: #8b1e3f;">$${item.precio.toFixed(2)}</span>
                    </div>
                    <button class="add-to-cart" data-id="${id}" style="margin-top: 10px; width: 100%; background: #8b1e3f; color: white; border: none; padding: 8px; border-radius: 5px; cursor: pointer;">
                        <i class="fas fa-plus"></i> Agregar
                    </button>
                </div>
            `;
            container.appendChild(card);
        }
    });
    
    document.querySelectorAll('.add-to-cart').forEach(btn => {
        btn.addEventListener('click', (e) => {
            const id = btn.getAttribute('data-id');
            addToCart(parseInt(id));
        });
    });
}

// Carrito de compras
let cart = [];

function addToCart(itemId) {
    const item = menuData[itemId];
    if (item) {
        cart.push(item);
        updateCartDisplay();
        Swal.fire({
            title: '¡Agregado!',
            text: `${item.nombre} añadido al carrito`,
            icon: 'success',
            timer: 1500,
            showConfirmButton: false
        });
    }
}

// Eliminar un producto específico del carrito
window.removeFromCart = function(index) {
    cart.splice(index, 1);
    updateCartDisplay();
    Swal.fire({
        title: 'Eliminado',
        text: 'Producto eliminado del carrito',
        icon: 'success',
        timer: 1500,
        showConfirmButton: false
    });
};

function updateCartDisplay() {
    const orderList = document.getElementById('order-list');
    const totalSpan = document.getElementById('total');
    
    if (!orderList) return;
    
    if (cart.length === 0) {
        orderList.innerHTML = '<li style="text-align:center; color:#999;">Carrito vacío</li>';
        if (totalSpan) totalSpan.textContent = '0.00';
        return;
    }
    
    orderList.innerHTML = '';
    let total = 0;
    
    cart.forEach((item, index) => {
        total += item.precio;
        const li = document.createElement('li');
        li.style.display = 'flex';
        li.style.justifyContent = 'space-between';
        li.style.alignItems = 'center';
        li.style.marginBottom = '8px';
        li.style.padding = '5px';
        li.style.borderBottom = '1px solid #eee';
        li.innerHTML = `
            <span>${item.nombre} - $${item.precio.toFixed(2)}</span>
            <button onclick="window.removeFromCart(${index})" style="background:#ff4444; color:white; border:none; border-radius:5px; padding:3px 8px; cursor:pointer;">
                <i class="fas fa-trash"></i>
            </button>
        `;
        orderList.appendChild(li);
    });
    
    if (totalSpan) totalSpan.textContent = total.toFixed(2);
}

// Mostrar reserva activa
function showActiveReservation() {
    const badge = document.getElementById('active-res-info');
    if (badge && currentReservation) {
        badge.innerHTML = `
            <i class="fas fa-calendar-check"></i> 
            Reserva: ${currentReservation.name} | ${currentReservation.date} | ${currentReservation.time} | ${currentReservation.people} ${currentReservation.people == 1 ? 'persona' : 'personas'}
        `;
        badge.style.display = 'block';
    } else if (badge) {
        badge.style.display = 'none';
    }
}

// Función para enviar correo electrónico con EmailJS
window.sendOrderEmail = async function(reservation, orderItems, total) {
    let userEmail = getCurrentUserEmail();
    
    console.log('========================================');
    console.log('📧 EMAIL OBTENIDO:', userEmail);
    console.log('========================================');
    
    if (!userEmail) {
        Swal.fire('Error', 'No se encontró el email del usuario logueado', 'error');
        return false;
    }
    
    let orderText = '';
    const grouped = {};
    orderItems.forEach(item => {
        const key = item.nombre;
        if (grouped[key]) {
            grouped[key].cantidad++;
            grouped[key].subtotal += item.precio;
        } else {
            grouped[key] = { ...item, cantidad: 1, subtotal: item.precio };
        }
    });
    
    Object.values(grouped).forEach(group => {
        orderText += `${group.cantidad}x ${group.nombre} - $${group.subtotal.toFixed(2)}\n`;
    });
    
    Swal.fire({
        title: 'Enviando correo...',
        text: `Enviando comprobante a ${userEmail}`,
        allowOutsideClick: false,
        didOpen: () => {
            Swal.showLoading();
        }
    });
    
    try {
        const serviceId = "service_d503f9k";
        const templateId = "template_koim2d9";
        
        const templateParams = {
            to_email: userEmail,
            to_name: reservation.name,
            reservation_date: reservation.date,
            reservation_time: reservation.time,
            reservation_people: reservation.people,
            order_details: orderText,
            total_amount: total.toFixed(2),
            restaurant_name: "Sabores de Lisboa",
            restaurant_address: "Rua Augusta, 124 - Lisboa",
            restaurant_phone: "+351 210 123 456"
        };
        
        await emailjs.send(serviceId, templateId, templateParams);
        
        Swal.fire({
            title: '¡Correo Enviado!',
            html: `Se ha enviado el comprobante a:<br><strong>${userEmail}</strong>`,
            icon: 'success',
            confirmButtonText: 'OK'
        });
        return true;
        
    } catch (error) {
        console.error('Error al enviar correo:', error);
        Swal.fire({
            title: 'Error al enviar correo',
            html: `No se pudo enviar el correo a ${userEmail}`,
            icon: 'error',
            confirmButtonText: 'OK'
        });
        return false;
    }
};

// Eliminar un pedido del historial
window.deleteOrderFromHistory = async function(orderIndex) {
    const result = await Swal.fire({
        title: '¿Eliminar pedido?',
        text: 'Esta acción no se puede deshacer',
        icon: 'warning',
        showCancelButton: true,
        confirmButtonColor: '#d33',
        cancelButtonColor: '#3085d6',
        confirmButtonText: 'Sí, eliminar',
        cancelButtonText: 'Cancelar'
    });
    
    if (result.isConfirmed) {
        const userId = getCurrentUserId();
        const orders = JSON.parse(localStorage.getItem(`orders_${userId}`) || '[]');
        orders.splice(orderIndex, 1);
        localStorage.setItem(`orders_${userId}`, JSON.stringify(orders));
        loadHistory();
        Swal.fire('Eliminado', 'Pedido eliminado del historial', 'success');
    }
};

// Eliminar una reserva del historial
window.deleteReservationFromHistory = async function(reservationIndex) {
    const result = await Swal.fire({
        title: '¿Eliminar reserva?',
        text: 'Esta acción no se puede deshacer',
        icon: 'warning',
        showCancelButton: true,
        confirmButtonColor: '#d33',
        cancelButtonColor: '#3085d6',
        confirmButtonText: 'Sí, eliminar',
        cancelButtonText: 'Cancelar'
    });
    
    if (result.isConfirmed) {
        const userId = getCurrentUserId();
        const reservations = JSON.parse(localStorage.getItem(`reservations_${userId}`) || '[]');
        reservations.splice(reservationIndex, 1);
        localStorage.setItem(`reservations_${userId}`, JSON.stringify(reservations));
        loadHistory();
        Swal.fire('Eliminada', 'Reserva eliminada del historial', 'success');
    }
};

// Función para crear el ticket HTML
function createTicketHTML(reservation, orderItems, total, userEmail, fechaActual) {
    let orderHtml = '';
    if (orderItems && orderItems.length > 0) {
        const grouped = {};
        orderItems.forEach(item => {
            const key = item.nombre;
            if (grouped[key]) {
                grouped[key].cantidad++;
                grouped[key].subtotal += item.precio;
            } else {
                grouped[key] = { ...item, cantidad: 1, subtotal: item.precio };
            }
        });
        
        Object.values(grouped).forEach(group => {
            orderHtml += `
                <tr>
                    <td style="padding: 8px; border-bottom: 1px solid #eee;">${group.cantidad}x ${group.nombre}</td>
                    <td style="padding: 8px; border-bottom: 1px solid #eee; text-align: right;">$${group.subtotal.toFixed(2)}</td>
                </tr>
            `;
        });
    } else {
        orderHtml = '</table><td colspan="2" style="padding: 8px; text-align: center;">Sin pedido</td></tr>';
    }
    
    return `
        <div id="ticket-print" style="font-family: 'Courier New', monospace; padding: 20px; background: white; width: 100%; box-sizing: border-box;">
            <div style="text-align: center; border-bottom: 2px dashed #8b1e3f; padding-bottom: 15px; margin-bottom: 15px;">
                <h2 style="color: #8b1e3f; margin: 0;">🍽️ Sabores de Lisboa</h2>
                <p style="margin: 5px 0;">Gastronomía de Autor</p>
                <p style="font-size: 12px; margin: 5px 0;">Rua Augusta, 124 - Lisboa</p>
                <p style="font-size: 12px; margin: 5px 0;">Tel: +351 210 123 456</p>
            </div>
            
            <div style="margin-bottom: 15px;">
                <h3 style="color: #8b1e3f; margin: 0 0 10px 0;">📋 COMPROBANTE DE RESERVA</h3>
                <table style="width: 100%; font-size: 13px;">
                    <tr><td style="padding: 4px 0;"><strong>Cliente:</strong></td><td style="padding: 4px 0;">${reservation.name}</td></tr>
                    <tr><td style="padding: 4px 0;"><strong>Email:</strong></td><td style="padding: 4px 0;">${userEmail}</td></tr>
                    <tr><td style="padding: 4px 0;"><strong>Fecha:</strong></td><td style="padding: 4px 0;">${reservation.date}</td></tr>
                    <tr><td style="padding: 4px 0;"><strong>Hora:</strong></td><td style="padding: 4px 0;">${reservation.time}</td></tr>
                    <tr><td style="padding: 4px 0;"><strong>Personas:</strong></td><td style="padding: 4px 0;">${reservation.people} ${reservation.people == 1 ? 'persona' : 'personas'}</td></tr>
                    <tr><td style="padding: 4px 0;"><strong>Mesa:</strong></td><td style="padding: 4px 0;">Asignada al llegar</td></tr>
                </table>
            </div>
            
            <div style="margin-bottom: 15px;">
                <h3 style="color: #8b1e3f; margin: 0 0 10px 0;">🛍️ DETALLE DEL PEDIDO</h3>
                <table style="width: 100%; font-size: 13px; border-collapse: collapse;">
                    <thead>
                        <tr style="background: #f5f5f5;">
                            <th style="border-bottom: 1px solid #ddd; padding: 8px; text-align: left;">Producto</th>
                            <th style="border-bottom: 1px solid #ddd; padding: 8px; text-align: right;">Subtotal</th>
                        </tr>
                    </thead>
                    <tbody>${orderHtml}</tbody>
                    <tfoot>
                        <tr style="border-top: 2px solid #333;">
                            <td style="padding: 10px 8px; font-weight: bold;">TOTAL</td>
                            <td style="padding: 10px 8px; font-weight: bold; text-align: right;">$${total.toFixed(2)}</td>
                        </tr>
                    </tfoot>
                </table>
            </div>
            
            <div style="text-align: center; border-top: 2px dashed #8b1e3f; padding-top: 15px; margin-top: 15px; font-size: 11px; color: #666;">
                <p style="margin: 5px 0;">✨ Le esperamos con los mejores sabores de Lisboa ✨</p>
                <p style="margin: 5px 0;">Por favor, presente este comprobante al llegar</p>
                <p style="margin: 5px 0;">Cancelaciones sin cargo hasta 2 horas antes</p>
                <p style="margin-top: 10px;">Emitido: ${fechaActual}</p>
                <p>Código: RES-${Math.random().toString(36).substr(2, 8).toUpperCase()}</p>
            </div>
        </div>
    `;
}

// Generar ticket con diseño mejorado
window.generateTicket = function(reservation, orderItems, total) {
    const ticketContent = document.getElementById('ticket-content');
    if (!ticketContent) return;
    
    currentOrderTotal = total;
    const fechaActual = new Date().toLocaleString('es-ES');
    const userEmail = getCurrentUserEmail() || 'cliente@email.com';
    
    const ticketHTML = createTicketHTML(reservation, orderItems, total, userEmail, fechaActual);
    ticketContent.innerHTML = ticketHTML;
};

